-- Seed de jerarquia curricular ACC (Modulo -> Submodulo -> Tema -> Subtema)
-- Generado desde ACC-SubmodulosProfundizados.docx
-- Convencion actual: sin lecciones en este script

USE [ACC_Academic];
GO

SET NOCOUNT ON;
SET XACT_ABORT ON;

BEGIN TRY
    BEGIN TRAN;

    IF EXISTS (SELECT 1 FROM acc_academic.Modulos)
       OR EXISTS (SELECT 1 FROM acc_academic.SubModulos)
       OR EXISTS (SELECT 1 FROM acc_academic.Temas)
       OR EXISTS (SELECT 1 FROM acc_academic.SubTemas)
    BEGIN
        THROW 50001, 'Las tablas de jerarquia ya contienen datos. Este seed consecutivo requiere tablas vacias.', 1;
    END;

    SET IDENTITY_INSERT acc_academic.Modulos ON;
    SET IDENTITY_INSERT acc_academic.Modulos OFF;

    SET IDENTITY_INSERT acc_academic.SubModulos ON;
    SET IDENTITY_INSERT acc_academic.SubModulos OFF;

    SET IDENTITY_INSERT acc_academic.Temas ON;
    SET IDENTITY_INSERT acc_academic.Temas OFF;

    SET IDENTITY_INSERT acc_academic.SubTemas ON;
    SET IDENTITY_INSERT acc_academic.SubTemas OFF;

    COMMIT TRAN;

    SELECT
        (SELECT COUNT(*) FROM acc_academic.Modulos) AS TotalModulos,
        (SELECT COUNT(*) FROM acc_academic.SubModulos) AS TotalSubModulos,
        (SELECT COUNT(*) FROM acc_academic.Temas) AS TotalTemas,
        (SELECT COUNT(*) FROM acc_academic.SubTemas) AS TotalSubTemas;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRAN;
    THROW;
END CATCH;
