    INSERT INTO acc_academic.Modulos (Id_Modulo, NombreModulo, DescripcionModulo)
    VALUES
        (1, N'Modulo I: Desarrolla software de sistemas informaticos', N'Presenta fundamentos de diseño, codificacion e implementacion para construir una base tecnica ordenada durante las primeras etapas del recorrido academico.'),
        (2, N'Modulo II: Desarrolla software con herramientas orientadas a la productividad', N'Aborda herramientas de productividad y frameworks para organizar mejor el trabajo tecnico y ampliar el alcance de las soluciones desarrolladas.'),
        (3, N'Modulo III: Desarrolla aplicaciones web.', N'Describe la ruta de desarrollo web con enfoque en estructura de aplicaciones, integracion de componentes y criterios de mantenibilidad.'),
        (4, N'Modulo IV: Desarrolla aplicaciones moviles multiplataforma.', N'Describe la ruta de desarrollo movil multiplataforma con enfasis en arquitectura, reutilizacion de codigo y consistencia de experiencia.');
    INSERT INTO acc_academic.SubModulos (Id_SubModulo, NombreSubModulo, DescripcionSubModulo, Id_Modulo)
    VALUES
        (1, N'Submodulo 1.1: Diseña software de sistemas informaticos', N'Introduce principios y tecnicas de diseño para estructurar soluciones antes de codificar y reducir errores de planteamiento.', 1),
        (2, N'Submodulo 1.2: Codifica software de sistemas informaticos', N'Explica fundamentos de programacion en C# y practica de codificacion para construir logica funcional con estructura clara.', 1),
        (3, N'Submodulo 1.3: Implementa software de sistemas informaticos', N'Aborda integracion, validaciones, pruebas y refactorizacion para convertir componentes tecnicos en soluciones completas y operativas.', 1),
        (4, N'Submodulo 2.1: Emplea frameworks para el desarrollo de software', N'Presenta frameworks y herramientas del ecosistema .NET para mejorar productividad y estandarizar procesos de desarrollo.', 2),
        (5, N'Submodulo 3.1: Desarrollo de aplicaciones web', N'Describe una base inicial para el desarrollo web y prepara la transicion hacia contenidos de implementacion especifica.', 3),
        (6, N'Submodulo 4.1: Desarrollo de aplicaciones moviles multiplataforma', N'Describe una base inicial para desarrollo movil multiplataforma y prepara la transicion hacia contenidos de implementacion especifica.', 4);
    INSERT INTO acc_academic.Temas (Id_Tema, NombreTema, DescripcionTema, Id_SubModulo)
    VALUES
        (1, N'Fundamentos del diseño de software', N'Presenta fundamentos del diseño de software a traves de subtemas que explican que es el diseño de software? y fases del diseño en el ciclo de vida con enfoque tecnico y secuencia progresiva.', 1),
        (2, N'Metodologias de desarrollo de software', N'Explica metodologias de desarrollo de software mediante contenidos que describen que es una metodologia de desarrollo de software? y relacionan metodologia cascada (waterfall) con decisiones de desarrollo.', 1),
        (3, N'Modelado funcional: E-R, E-P-S, DFD', N'Aborda modelado funcional: e-r, e-p-s, dfd con una secuencia de subtemas centrada en que es el modelado funcional en software? y su aplicacion dentro de ejercicios practicos.', 1),
        (4, N'Diagramas de flujo detallados', N'Analiza diagramas de flujo detallados integrando subtemas sobre que es un diagrama de flujo? y simbologia estandar de diagramas de flujo para mantener continuidad entre teoria y practica.', 1),
        (5, N'Introduccion al modelado UML', N'Presenta introduccion al modelado uml a traves de subtemas que explican que es uml y para que se utiliza? y breve historia y evolucion de uml con enfoque tecnico y secuencia progresiva.', 1),
        (6, N'Casos de uso: actores y procesos', N'Explica casos de uso: actores y procesos mediante contenidos que describen que es un caso de uso? y relacionan identificacion de actores con decisiones de desarrollo.', 1),
        (7, N'Diagramas de clases y relaciones', N'Aborda diagramas de clases y relaciones con una secuencia de subtemas centrada en que es un diagrama de clases? y su aplicacion dentro de ejercicios practicos.', 1),
        (8, N'Diseño de arquitectura: capas, servicios y patrones', N'Analiza diseño de arquitectura: capas, servicios y patrones integrando subtemas sobre que es una arquitectura de software? y principios de separacion de responsabilidades para mantener continuidad entre teoria y practica.', 1),
        (9, N'Diseño logico: pseudocodigo y algoritmos', N'Presenta diseño logico: pseudocodigo y algoritmos a traves de subtemas que explican que es el diseño logico en el desarrollo de software? y que es un algoritmo? con enfoque tecnico y secuencia progresiva.', 1),
        (10, N'Estructuras de control aplicadas al diseño', N'Explica estructuras de control aplicadas al diseño mediante contenidos que describen que son las estructuras de control? y relacionan condicionales simples (if, if-else) con decisiones de desarrollo.', 1),
        (11, N'Modularidad y componentes en diseño', N'Aborda modularidad y componentes en diseño con una secuencia de subtemas centrada en que es la modularidad en el diseño de software? y su aplicacion dentro de ejercicios practicos.', 1),
        (12, N'Diseño de interfaces preliminares (mockups)', N'Analiza diseño de interfaces preliminares (mockups) integrando subtemas sobre que es una interfaz de usuario (ui)? y que es un mockup y para que se utiliza? para mantener continuidad entre teoria y practica.', 1),
        (13, N'Herramientas de modelado (Lucidchart, Draw.io, StarUML)', N'Presenta herramientas de modelado (lucidchart, draw.io, staruml) a traves de subtemas que explican por que usar herramientas de modelado? y lucidchart: caracteristicas y uso basico con enfoque tecnico y secuencia progresiva.', 1),
        (14, N'Documentacion tecnica del diseño', N'Explica documentacion tecnica del diseño mediante contenidos que describen que es la documentacion tecnica en software? y relacionan tipos de documentacion en el diseño de software con decisiones de desarrollo.', 1),
        (15, N'Validacion del diseño', N'Aborda validacion del diseño con una secuencia de subtemas centrada en por que validar un diseño de software? y su aplicacion dentro de ejercicios practicos.', 1),
        (16, N'Refactorizacion y adaptacion del diseño', N'Analiza refactorizacion y adaptacion del diseño integrando subtemas sobre que es la refactorizacion de diseño? y causas comunes para refactorizar un diseño para mantener continuidad entre teoria y practica.', 1),
        (17, N'Introduccion al lenguaje de programacion C#', N'Presenta introduccion al lenguaje de programacion c# a traves de subtemas que explican que es c# y por que aprenderlo? y historia breve y evolucion de c# con enfoque tecnico y secuencia progresiva.', 2),
        (18, N'Entornos de desarrollo para C#', N'Explica entornos de desarrollo para c# mediante contenidos que describen que es un entorno de desarrollo (ide)? y relacionan visual studio: entorno oficial de .net con decisiones de desarrollo.', 2),
        (19, N'Instalacion y configuracion de Visual Studio', N'Aborda instalacion y configuracion de visual studio con una secuencia de subtemas centrada en descarga de visual studio community edition y su aplicacion dentro de ejercicios practicos.', 2),
        (20, N'Tipos de datos, variables y constantes', N'Analiza tipos de datos, variables y constantes integrando subtemas sobre que es una variable? y tipos de datos primitivos en c# para mantener continuidad entre teoria y practica.', 2),
        (21, N'Entrada y salida de datos', N'Presenta entrada y salida de datos a traves de subtemas que explican console.writeline y console.write y console.readline, console.read y console.readkey para entrada de datos con enfoque tecnico y secuencia progresiva.', 2),
        (22, N'Operadores y expresiones', N'Explica operadores y expresiones mediante contenidos que describen operadores aritmeticos y relacionan operadores de asignacion con decisiones de desarrollo.', 2),
        (23, N'Estructuras de control de flujo', N'Aborda estructuras de control de flujo con una secuencia de subtemas centrada en condicionales: if, else if, else y su aplicacion dentro de ejercicios practicos.', 2),
        (24, N'Arreglos unidimensionales', N'Analiza arreglos unidimensionales integrando subtemas sobre que es un arreglo (array)? y declaracion y creacion de arreglos para mantener continuidad entre teoria y practica.', 2),
        (25, N'Listas', N'Presenta listas a traves de subtemas que explican que es una lista (list<t>) y por que usarla? y declaracion y creacion de listas con enfoque tecnico y secuencia progresiva.', 2),
        (26, N'Metodos y modularidad', N'Explica metodos y modularidad mediante contenidos que describen que es un metodo y por que usarlo? y relacionan declaracion y sintaxis basica de metodos con decisiones de desarrollo.', 2),
        (27, N'Introduccion a la Programacion Orientada a Objetos (POO)', N'Aborda introduccion a la programacion orientada a objetos (poo) con una secuencia de subtemas centrada en que es la programacion orientada a objetos? y su aplicacion dentro de ejercicios practicos.', 2),
        (28, N'Proyecto Integrador I: Diseño y Codificacion Basica', N'Analiza proyecto integrador i: diseño y codificacion basica integrando subtemas sobre descripcion general del proyecto y aplicacion practica para mantener continuidad entre teoria y practica.', 2),
        (29, N'Organizacion tecnica del proyecto y puesta en marcha', N'Presenta organizacion tecnica del proyecto y puesta en marcha a traves de subtemas que explican revision tecnica del entorno de desarrollo y estructura logica de carpetas y namespaces con enfoque tecnico y secuencia progresiva.', 3),
        (30, N'Integracion de clases, listas y logica funcional', N'Explica integracion de clases, listas y logica funcional mediante contenidos que describen comunicacion entre clases y relacionan uso correcto de listas dinamicas (list<t>) para almacenar entidades con decisiones de desarrollo.', 3),
        (31, N'Programacion orientada a objetos - Parte II: Profundizacion', N'Aborda programacion orientada a objetos - parte ii: profundizacion con una secuencia de subtemas centrada en principios de encapsulamiento avanzado y su aplicacion dentro de ejercicios practicos.', 3),
        (32, N'Lectura y escritura de archivos con System.IO', N'Analiza lectura y escritura de archivos con system.io integrando subtemas sobre introduccion a la persistencia local con archivos y escritura de archivos con streamwriter y file.writealltext para mantener continuidad entre teoria y practica.', 3),
        (33, N'Validacion robusta y manejo estructurado de errores', N'Presenta validacion robusta y manejo estructurado de errores a traves de subtemas que explican validacion de entrada de datos en consola y uso de try, catch, finally para capturar errores con enfoque tecnico y secuencia progresiva.', 3),
        (34, N'Pruebas funcionales manuales y validacion por escenarios', N'Explica pruebas funcionales manuales y validacion por escenarios mediante contenidos que describen que son las pruebas funcionales? y relacionan diseño de casos de prueba simples con decisiones de desarrollo.', 3),
        (35, N'Refactorizacion tecnica y mejora del codigo fuente', N'Aborda refactorizacion tecnica y mejora del codigo fuente con una secuencia de subtemas centrada en que es refactorizar y por que hacerlo? y su aplicacion dentro de ejercicios practicos.', 3),
        (36, N'Documentacion tecnica del codigo implementado', N'Analiza documentacion tecnica del codigo implementado integrando subtemas sobre que es la documentacion tecnica y para que sirve? y comentarios xml en c# (///) para mantener continuidad entre teoria y practica.', 3),
        (37, N'Proyecto funcional integrador II: Sistema con validaciones, persistencia y documentacion', N'Presenta proyecto funcional integrador ii: sistema con validaciones, persistencia y documentacion a traves de subtemas que explican presentacion del reto: sistema funcional y requisitos tecnicos del proyecto con enfoque tecnico y secuencia progresiva.', 3),
        (38, N'Introduccion a los frameworks de desarrollo', N'Explica introduccion a los frameworks de desarrollo mediante contenidos que describen conceptos clave de introduccion a los frameworks de desarrollo y relacionan aplicacion practica con decisiones de desarrollo.', 4),
        (39, N'Arquitectura del ecosistema .NET', N'Aborda arquitectura del ecosistema .net con una secuencia de subtemas centrada en conceptos clave de arquitectura del ecosistema .net y su aplicacion dentro de ejercicios practicos.', 4),
        (40, N'Configuracion del entorno de trabajo en Visual Studio', N'Analiza configuracion del entorno de trabajo en visual studio integrando subtemas sobre conceptos clave de configuracion del entorno de trabajo en visual studio y aplicacion practica para mantener continuidad entre teoria y practica.', 4),
        (41, N'Fundamentos de interfaces graficas con WinForms o WPF', N'Presenta fundamentos de interfaces graficas con winforms o wpf a traves de subtemas que explican conceptos clave de fundamentos de interfaces graficas con winforms o wpf y aplicacion practica con enfoque tecnico y secuencia progresiva.', 4),
        (42, N'Introduccion al acceso a datos con ADO.NET', N'Explica introduccion al acceso a datos con ado.net mediante contenidos que describen conceptos clave de introduccion al acceso a datos con ado.net y relacionan aplicacion practica con decisiones de desarrollo.', 4),
        (43, N'Uso de herramientas de productividad en .NET (LINQ, NuGet)', N'Aborda uso de herramientas de productividad en .net (linq, nuget) con una secuencia de subtemas centrada en conceptos clave de uso de herramientas de productividad en .net (linq, nuget) y su aplicacion dentro de ejercicios practicos.', 4),
        (44, N'Buenas practicas de desarrollo con frameworks', N'Analiza buenas practicas de desarrollo con frameworks integrando subtemas sobre conceptos clave de buenas practicas de desarrollo con frameworks y aplicacion practica para mantener continuidad entre teoria y practica.', 4),
        (45, N'Proyecto integrador con WinForms y ADO.NET', N'Presenta proyecto integrador con winforms y ado.net a traves de subtemas que explican conceptos clave de proyecto integrador con winforms y ado.net y aplicacion practica con enfoque tecnico y secuencia progresiva.', 4),
        (46, N'Fundamentos de desarrollo web', N'Explica fundamentos de desarrollo web mediante contenidos que describen arquitectura inicial de aplicaciones web y relacionan aplicacion practica con decisiones de desarrollo.', 5),
        (47, N'Fundamentos de desarrollo movil multiplataforma', N'Aborda fundamentos de desarrollo movil multiplataforma con una secuencia de subtemas centrada en arquitectura inicial de apps moviles y su aplicacion dentro de ejercicios practicos.', 6);
    INSERT INTO acc_academic.SubTemas (Id_SubTema, NombreSubTema, DescripcionSubTema, Id_Tema)
    VALUES
        (1, N'Que es el diseño de software?', N'Introduce el concepto, su papel en el ciclo de vida del software y su proposito', 1),
        (2, N'Fases del diseño en el ciclo de vida', N'Explica en que parte del desarrollo entra el diseño y sus interacciones con analisis e implementacion', 1),
        (3, N'Tipos de diseño: logico vs fisico', N'Diferencia los niveles de abstraccion en el diseño (logico, arquitectonico, fisico)', 1),
        (4, N'Principios fundamentales del buen diseño', N'Introduce conceptos como cohesion, acoplamiento, responsabilidad unica, reutilizacion', 1),
        (5, N'Ventajas de un buen diseño vs consecuencias de uno malo', N'Reflexion critica apoyada con ejemplos (positivos y negativos)', 1),
        (6, N'Diseño de software vs diseño grafico vs diseño UX', N'Aclara diferencias entre areas comunmente confundidas', 1),
        (7, N'Que es una metodologia de desarrollo de software?', N'Define que es una metodologia, por que es necesaria y como influye en el exito de un proyecto', 2),
        (8, N'Metodologia Cascada (Waterfall)', N'Explica sus fases, estructura secuencial y cuando se recomienda', 2),
        (9, N'Metodologias Agiles: introduccion y principios', N'Presenta el Manifiesto Agil y el enfoque iterativo/incremental', 2),
        (10, N'Scrum: roles, artefactos y sprints', N'Aborda la metodologia agil mas usada en la industria con sus elementos clave', 2),
        (11, N'Kanban: flujo visual y control de trabajo', N'Introduce esta tecnica agil visual, ideal para gestion de tareas', 2),
        (12, N'Comparativa entre metodologias: cuando usar cada una', N'Tabla comparativa sencilla entre cascada, agil, Scrum y Kanban. Casos practicos', 2),
        (13, N'Herramientas comunes: Trello, Azure DevOps, Jira', N'Muestra ejemplos reales de como se aplican estas metodologias en herramientas actuales', 2),
        (14, N'Que es el modelado funcional en software?', N'Presenta el proposito general de modelar un sistema antes de desarrollarlo', 3),
        (15, N'Introduccion a los Diagramas Entidad-Relacion (E-R)', N'Explica que son, cuando se usan y su relacion con las bases de datos', 3),
        (16, N'Elementos clave del Diagrama E-R', N'Atributos, entidades, relaciones, cardinalidades, tipos de relaciones', 3),
        (17, N'Introduccion al Diagrama Entrada-Proceso-Salida (E-P-S)', N'Muestra como visualizar la transformacion de datos en un sistema', 3),
        (18, N'Ejemplo practico de diagrama E-P-S', N'Construye uno paso a paso con un caso sencillo (ej. sistema de ventas)', 3),
        (19, N'Introduccion al Diagrama de Flujo de Datos (DFD)', N'Explica niveles de abstraccion, procesos, almacenes, flujos y entidades externas', 3),
        (20, N'Diferencias entre E-R, E-P-S y DFD', N'Comparacion clara de proposito, simbolo y uso', 3),
        (21, N'Buenas practicas al modelar', N'Consejos para claridad, consistencia y logica en los diagramas funcionales', 3),
        (22, N'Que es un diagrama de flujo?', N'Definirlo como herramienta visual para representar algoritmos o procesos', 4),
        (23, N'Simbologia estandar de diagramas de flujo', N'Explica los simbolos: inicio/fin, procesos, decisiones, entradas/salidas, conectores', 4),
        (24, N'Reglas y buenas practicas de diagramacion', N'Flujo vertical, claridad, uso de conectores, etiquetas significativas', 4),
        (25, N'Ejemplo guiado: diagrama de flujo de un programa basico', N'Construye uno paso a paso (ej. calculo de promedio o acceso a sistema)', 4),
        (26, N'Ejercicios de interpretacion', N'Leer y entender diagramas ya hechos, identificar errores logicos o de secuencia', 4),
        (27, N'Diagramas de flujo vs pseudocodigo', N'Compara ventajas, cuando usar cada uno, como se complementan', 4),
        (28, N'Que es UML y para que se utiliza?', N'Explica que UML es un lenguaje grafico para representar sistemas orientados a objetos', 5),
        (29, N'Breve historia y evolucion de UML', N'Origen, estandarizacion por la OMG y su relevancia actual', 5),
        (30, N'Tipos de diagramas UML: estructurales vs de comportamiento', N'Clasificacion general para orientar al estudiante sobre su diversidad', 5),
        (31, N'Diagramas mas comunes en el desarrollo de software', N'Enfatizar: clases, casos de uso, secuencia y actividades', 5),
        (32, N'Reglas y convenciones basicas de notacion UML', N'Como dibujar correctamente relaciones, atributos, operaciones, etc', 5),
        (33, N'Diferencias entre UML y otros esquemas de modelado', N'Contrastar con E-R, EPS, DFD, diagramas de flujo, etc', 5),
        (34, N'Que es un caso de uso?', N'Definirlo como una descripcion de una interaccion entre un actor y el sistema', 6),
        (35, N'Identificacion de actores', N'Explica que es un actor (usuario, sistema externo, dispositivo) y como detectarlos', 6),
        (36, N'Identificacion de procesos (escenarios de uso)', N'Como definir los procesos clave que debe cubrir el sistema', 6),
        (37, N'Diagrama de casos de uso: notacion y estructura', N'Introduccion al diagrama con actores, casos y relaciones (include, extend)', 6),
        (38, N'Ejemplo completo de caso de uso', N'Construye un caso simple (ej. "usuario inicia sesion" o "cliente realiza pedido")', 6),
        (39, N'Buenas practicas y errores comunes en casos de uso', N'Claridad en nombres, evitar tecnicismos, mantener enfoque funcional', 6),
        (40, N'Que es un diagrama de clases?', N'Introducirlo como representacion estructural de un sistema OO', 7),
        (41, N'Elementos de una clase: atributos, metodos y visibilidad', N'Explica como se representan los miembros y su acceso (+, -, #)', 7),
        (42, N'Relaciones entre clases: asociacion, agregacion, composicion', N'Distingue los tipos de relaciones con ejemplos claros', 7),
        (43, N'Herencia y generalizacion en UML', N'Muestra como representar jerarquias y clases base', 7),
        (44, N'Notacion y convenciones del diagrama de clases', N'Explica la sintaxis formal y organizacion visual', 7),
        (45, N'Ejemplo practico: modelado de un sistema sencillo', N'Ej. sistema de biblioteca, tienda o usuarios con roles', 7),
        (46, N'Buenas practicas de modelado de clases', N'Mantener cohesion, evitar acoplamiento innecesario, claridad en nombres', 7),
        (47, N'Que es una arquitectura de software?', N'Definirla como el diseño estructural de alto nivel de un sistema', 8),
        (48, N'Principios de separacion de responsabilidades', N'Introduce SRP, modularidad, mantenibilidad y escalabilidad', 8),
        (49, N'Arquitectura en capas: presentacion, logica y datos', N'Explica el modelo clasico de tres capas y su proposito', 8),
        (50, N'Servicios y componentes: definicion y proposito', N'Define un servicio, que hace, y como se desacopla del resto del sistema', 8),
        (51, N'Patron MVC: Modelo-Vista-Controlador', N'Explica su estructura, roles y aplicacion comun en web/desktops', 8),
        (52, N'Patron MVVM: Modelo-Vista-VistaModelo', N'Introduccion basica a este patron usado en interfaces modernas (WPF, MAUI)', 8),
        (53, N'Comparacion entre MVC y MVVM', N'Cuando usar cada uno, ventajas, herramientas compatibles', 8),
        (54, N'Ejemplo practico: arquitectura de una app simple', N'Representar visualmente la arquitectura de una app con capas y patron aplicado', 8),
        (55, N'Que es el diseño logico en el desarrollo de software?', N'Introduce el diseño logico como puente entre el problema y su implementacion', 9),
        (56, N'Que es un algoritmo?', N'Definirlo, sus caracteristicas (finito, definido, efectivo) y su rol en la solucion de problemas', 9),
        (57, N'Pseudocodigo: estructura basica y convenciones', N'Presenta una sintaxis estandar para representar algoritmos', 9),
        (58, N'Variables, operadores y asignacion en pseudocodigo', N'Explica como manejar informacion en este lenguaje intermedio', 9),
        (59, N'Condicionales y ciclos en pseudocodigo', N'Introduce estructuras de control: si, mientras, para, etc', 9),
        (60, N'Ejemplos practicos de algoritmos clasicos', N'Ej. suma de numeros, factorial, validacion de contrasenas, busqueda', 9),
        (61, N'Buenas practicas al escribir pseudocodigo', N'Claridad, coherencia, indentacion, comentarios breves y descriptivos', 9),
        (62, N'Conversion de pseudocodigo a codigo real', N'Muestra el proceso de transformacion del diseño logico a codigo C#', 9),
        (63, N'Que son las estructuras de control?', N'Introduce su papel en el flujo logico de cualquier algoritmo o proceso', 10),
        (64, N'Condicionales simples (if, if-else)', N'Diseñar decisiones binarias con resultados diferentes segun una condicion', 10),
        (65, N'Condicionales multiples (if-else if, switch)', N'Explica como elegir entre varias rutas posibles segun diferentes condiciones', 10),
        (66, N'Ciclos controlados por contador (for)', N'Explica como repetir acciones una cantidad determinada de veces', 10),
        (67, N'Ciclos controlados por condicion (while, do-while)', N'Explica como repetir mientras se cumpla una condicion logica', 10),
        (68, N'Control de flujo: break, continue y anidamiento', N'Introduce como modificar la ejecucion dentro de estructuras repetitivas', 10),
        (69, N'Errores comunes y buenas practicas en estructuras de control', N'Detecta fallos logicos, condiciones infinitas, y como evitarlos', 10),
        (70, N'Aplicacion de estructuras de control en el diseño de algoritmos', N'Integra lo aprendido para resolver problemas logicos reales antes de codificar', 10),
        (71, N'Que es la modularidad en el diseño de software?', N'Define el concepto y sus beneficios en sistemas complejos', 11),
        (72, N'Principios de diseño modular: cohesion y acoplamiento', N'Ensenar como evaluar la calidad de un modulo y su nivel de independencia', 11),
        (73, N'Componentes de software: definicion y tipos', N'Introduce que es un componente, su rol, y ejemplos reales', 11),
        (74, N'Division de funcionalidades en modulos', N'Estrategias para separar logica en unidades funcionales', 11),
        (75, N'Diseño de interfaces entre modulos', N'Explica como los modulos se comunican: entradas, salidas y contratos', 11),
